INSERT INTO news (id, slug, type, kicker, title, summary, image_url, image_alt, read_more_text, body_content, external_link, mentorship_data) VALUES
(
  'q2-mentorship-concluded-id', 
  'q2-mentorship-concluded', 
  'article', 
  'Mentorship · Announcement', 
  'Q2 Mentorship Programme Successfully Concluded', 
  'The BCL Q2 Mentorship Programme has concluded after six weeks of practical learning, reflection and application through the Engine Room Operations Framework.', 
  '/assets/images/bcl-q2-mentorship-cohort-collage.jpg', 
  'Beth Consulting Limited Q2 Mentorship Programme cohort collage', 
  'Read more →', 
  '<p>The Beth Consulting Limited Q2 Mentorship Programme has officially come to a close, marking six weeks of learning, reflection, and practical application.</p><p>Throughout the programme, participants explored the Engine Room Operations Framework (EROF), developing practical approaches to operational structure, documentation, workflow management, and decision support. More importantly, they challenged familiar ways of working and began applying new ideas within their organisations.</p><p>We are grateful to every participant for their commitment, thoughtful engagement, and willingness to learn. Your contributions made this cohort a rewarding experience and reinforced our commitment to developing administrative and operations professionals through practical, systems-focused learning.</p><p>As we celebrate the successful completion of this cohort, we look forward to welcoming future participants to upcoming mentorship programmes and learning opportunities.</p><p>Thank you for being part of the journey, and stay connected for announcements about future cohorts.</p><img src="/assets/images/bcl-q2-mentorship-voices-engine-room.jpg" alt="Voices from the Engine Room reflections from BCL Q2 Mentorship participants" style="width: 100%; height: auto; border-radius: 16px; box-shadow: var(--shadow); margin: 2.2rem 0" />', 
  NULL, 
  NULL
);

INSERT INTO news (id, slug, type, kicker, title, summary, image_url, image_alt, read_more_text, body_content, external_link, mentorship_data) VALUES
(
  'bcl-q2-mentorship-programme-id', 
  'bcl-q2-mentorship-programme', 
  'mentorship', 
  'Mentorship · Announcement', 
  'BCL Q2 Mentorship Programme', 
  'The programme returns this quarter with a more structured approach, built around the Engine Room Operations Framework.', 
  '/assets/images/event-q2-teaser.jpg', 
  'BCL Q2 Mentorship Programme announcement', 
  'Read more →', 
  '<p>Last quarter, Beth Consulting Limited ran its first mentorship cycle focused on administrative and operational growth. This quarter, the programme returns with a more structured approach under Beth Consulting Limited.</p><p>The Q2 Mentorship Programme commenced on 4 June 2026 and runs to 9 July 2026, built around the Engine Room Operations Framework. The focus is practical operational improvement, not motivational conversations.</p><p>The sessions are designed to help administrative and operations professionals improve how work is structured, communicated, tracked, reviewed and executed under pressure.</p><p><strong>This cohort is currently in progress (4 June – 9 July 2026).</strong></p>', 
  NULL, 
  '{"dates_tag":"Now running · 4 June – 9 July 2026","status_text":"Applications for this cohort are closed. Subscribe for the next one.","apply_link":"","weeks":[{"wk":"Week 01","title":"Alignment and Readiness"},{"wk":"Week 02","title":"Communication and Expectations"},{"wk":"Week 03","title":"Systems and Workflow"},{"wk":"Week 04","title":"Decision Support"},{"wk":"Week 05","title":"Performance and Review"},{"wk":"Week 06","title":"Stakeholder Management"}],"who_is_it_for":"Admin Professionals, Executive Assistants, Personal Assistants, Operations Support Professionals","what_you_will_get":"One-on-one coaching, Workflow structuring and execution support, Accountability and performance improvement, Practical workplace application using the Engine Room Operations Framework"}'
);

